import React, { useState, useEffect } from 'react';
import axios from 'axios';

export default function Marketplace() {
  const [activeTab, setActiveTab] = useState('all'); 
  const [loads, setLoads] = useState([]);
  const [form, setForm] = useState({ origin: '', destination: '', weight: '', pallets: '', price: '' });
  const [loading, setLoading] = useState(false);

  const currentUser = "Mohana Priya"; 

  const fetchData = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/loads/all");
      setLoads(res.data);
    } catch (err) { console.error(err); }
  };

  useEffect(() => { fetchData(); }, []);

  // --- DELETE LOGIC ---
  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this load?")) {
      try {
        await axios.delete(`http://localhost:5000/api/loads/delete/${id}`);
        fetchData(); // List-ah refresh pannum
      } catch (err) { alert("Delete failed"); }
    }
  };

  const handlePost = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await axios.post("http://localhost:5000/api/loads/add", { ...form, postedBy: currentUser });
      setForm({ origin: '', destination: '', weight: '', pallets: '', price: '' });
      fetchData();
    } catch (err) { alert("Error posting load"); }
    setLoading(false);
  };

  const handleBook = async (id) => {
    try {
      await axios.patch(`http://localhost:5000/api/loads/book/${id}`);
      fetchData();
    } catch (err) { console.error(err); }
  };

  const displayedLoads = activeTab === 'all' 
    ? loads 
    : loads.filter(l => l.postedBy === currentUser);

  return (
    <div className="min-h-screen bg-[#FFFBEB] font-sans text-slate-900">
      <nav className="sticky top-0 z-50 bg-[#E11D48] px-8 py-4 flex justify-between items-center shadow-xl">
        <div className="flex items-center gap-3">
          <div className="bg-white p-2 rounded-xl shadow-inner text-2xl">🚚</div>
          <h1 className="text-2xl font-black italic tracking-tighter text-white uppercase">Truck Board <span className="text-yellow-400">Pro</span></h1>
        </div>
        <button onClick={() => window.location.href='/login'} className="bg-black text-white px-6 py-2 rounded-full font-bold text-xs uppercase hover:bg-white hover:text-red-600 transition-all">Logout</button>
      </nav>

      <main className="max-w-[1400px] mx-auto p-8 grid grid-cols-1 lg:grid-cols-12 gap-10">
        
        {/* --- FORM SIDEBAR --- */}
        <aside className="lg:col-span-4">
          <div className="sticky top-28 bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 text-center">
               <h2 className="text-white text-xl font-black uppercase italic tracking-widest">New Dispatch</h2>
               <div className="h-1 w-12 bg-red-600 mx-auto mt-2 rounded-full"></div>
            </div>
            
            <form onSubmit={handlePost} className="p-8 space-y-4">
              <input type="text" placeholder="Origin" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.origin} onChange={e => setForm({...form, origin: e.target.value})} required />
              <input type="text" placeholder="Destination" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.destination} onChange={e => setForm({...form, destination: e.target.value})} required />
              <div className="grid grid-cols-2 gap-4">
                <input type="number" placeholder="Kg" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.weight} onChange={e => setForm({...form, weight: e.target.value})} required />
                <input type="number" placeholder="Plt" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.pallets} onChange={e => setForm({...form, pallets: e.target.value})} required />
              </div>
              <input type="number" placeholder="Price $" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-green-500 outline-none font-bold text-green-600" value={form.price} onChange={e => setForm({...form, price: e.target.value})} required />
              <button disabled={loading} className="w-full bg-red-600 text-white py-5 rounded-2xl font-black uppercase tracking-widest hover:bg-slate-900 transition-all shadow-lg active:scale-95">
                {loading ? 'Broadcasting...' : 'Broadcast Load'}
              </button>
            </form>
          </div>
        </aside>

        {/* --- FEED SECTION --- */}
        <section className="lg:col-span-8">
          <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
            <div className="bg-white p-1.5 rounded-2xl shadow-md flex border border-slate-200">
              <button onClick={() => setActiveTab('all')} className={`px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${activeTab === 'all' ? 'bg-red-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>All Shipments</button>
              <button onClick={() => setActiveTab('mine')} className={`px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${activeTab === 'mine' ? 'bg-red-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>My Posts</button>
            </div>
            <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Showing {displayedLoads.length} Loads</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {displayedLoads.map(l => (
              <div key={l._id} className={`group relative bg-white rounded-[2.5rem] p-8 transition-all border-2 ${l.isBooked ? 'bg-slate-50 opacity-60 border-transparent' : 'border-white hover:border-red-100 shadow-xl'}`}>
                
                {/* --- TRASH ICON --- */}
                {l.postedBy === currentUser && (
                  <button 
                    onClick={() => handleDelete(l._id)}
                    className="absolute top-8 right-8 text-slate-300 hover:text-red-600 transition-colors"
                    title="Delete Load"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                    </svg>
                  </button>
                )}

                <div className="flex justify-between items-start mb-6">
                   <div className={`${l.isBooked ? 'bg-slate-300' : 'bg-yellow-400'} text-[9px] font-black px-3 py-1 rounded-full uppercase`}>
                    {l.isBooked ? 'Booked' : 'Active'}
                  </div>
                  <div className="text-3xl font-black text-slate-900 tracking-tighter">${l.price}</div>
                </div>

                <div className="space-y-4 mb-6">
                  <h3 className="text-xl font-black text-slate-800 uppercase leading-none">{l.origin} ➔ {l.destination}</h3>
                  <div className="flex gap-4 text-xs font-bold text-slate-400 uppercase">
                    <span>{l.weight} kg</span>
                    <span>•</span>
                    <span>{l.pallets} Pallets</span>
                  </div>
                </div>

                {!l.isBooked ? (
                  <button onClick={() => handleBook(l._id)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase hover:bg-red-600 transition-colors shadow-lg">
                    Secure Booking
                  </button>
                ) : (
                  <div className="w-full bg-slate-200 text-slate-500 py-4 rounded-2xl font-black uppercase text-center italic text-sm border-2 border-dashed">
                    Shipment Sold
                  </div>
                )}
              </div>
            ))}
          </div>
        </section>
      </main>
    </div>
  );
}
